import os
import threading
import queue
import time
import logging
from flask import Flask, request, Response, send_file, abort
from werkzeug.utils import secure_filename

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'mp4', 'avi', 'mov', 'webm'}
CHUNK_SIZE = 1024 * 1024  # 1MB chunk size
MAX_UPLOAD_SIZE = 1024 * 1024 * 1024 * 2 # 2GB max upload size

# Ensure upload folder exists
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_UPLOAD_SIZE

# Logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Video Metadata (In-memory for simplicity, consider a database for production)
video_metadata = {}  # {video_id: {'filename': '...', 'resolutions': ['720p', '1080p']}}

# Transcoding Queue (Simulated)
transcoding_queue = queue.Queue()

# Helper Functions
def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def generate_video_id():
    return str(int(time.time())) # Simple ID generation

def get_video_path(video_id, resolution=None):
    """Returns the path to the video file, considering resolution."""
    if video_id not in video_metadata:
        return None

    filename = video_metadata[video_id]['filename']
    if resolution:
        base_name, ext = os.path.splitext(filename)
        return os.path.join(app.config['UPLOAD_FOLDER'], f"{base_name}_{resolution}{ext}")
    else:
        return os.path.join(app.config['UPLOAD_FOLDER'], filename)

def get_file_size(file_path):
    try:
        return os.path.getsize(file_path)
    except FileNotFoundError:
        return None

# Transcoding Worker (Simulated)
def transcoding_worker():
    while True:
        video_id = transcoding_queue.get()
        if video_id is None:  # Sentinel value to stop the worker
            break

        logging.info(f"Starting transcoding for video ID: {video_id}")

        # Simulate transcoding to different resolutions
        filename = video_metadata[video_id]['filename']
        base_name, ext = os.path.splitext(filename)
        original_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)

        # Simulate transcoding to 720p
        time.sleep(2)  # Simulate processing time
        with open(original_path, 'rb') as src, open(os.path.join(app.config['UPLOAD_FOLDER'], f"{base_name}_720p{ext}"), 'wb') as dest:
            dest.write(src.read()) # Copy for simulation
        logging.info(f"Transcoded to 720p for video ID: {video_id}")

        # Simulate transcoding to 1080p
        time.sleep(3)  # Simulate processing time
        with open(original_path, 'rb') as src, open(os.path.join(app.config['UPLOAD_FOLDER'], f"{base_name}_1080p{ext}"), 'wb') as dest:
            dest.write(src.read()) # Copy for simulation
        logging.info(f"Transcoded to 1080p for video ID: {video_id}")

        video_metadata[video_id]['resolutions'] = ['720p', '1080p']
        logging.info(f"Transcoding complete for video ID: {video_id}")
        transcoding_queue.task_done()

# Start Transcoding Worker
transcoding_thread = threading.Thread(target=transcoding_worker, daemon=True)
transcoding_thread.start()

# Routes
@app.route('/upload', methods=['POST'])
def upload_video():
    """Handles video uploads."""
    if 'video' not in request.files:
        return "No video file provided", 400

    video_file = request.files['video']

    if video_file.filename == '':
        return "No video file selected", 400

    if video_file and allowed_file(video_file.filename):
        filename = secure_filename(video_file.filename)
        video_id = generate_video_id()
        filename = f"{video_id}_{filename}" # Prepend video_id to filename
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        video_file.save(filepath)

        video_metadata[video_id] = {'filename': filename, 'resolutions': []}
        transcoding_queue.put(video_id) # Add to transcoding queue

        return f"Video uploaded successfully. Video ID: {video_id}", 201
    else:
        return "Invalid file type. Allowed types: mp4, avi, mov, webm", 400

@app.route('/video/<video_id>')
def get_video_info(video_id):
    """Returns video metadata."""
    if video_id not in video_metadata:
        return "Video not found", 404

    return video_metadata[video_id], 200

@app.route('/stream/<video_id>')
def stream_video(video_id):
    """Streams the video in chunks."""
    resolution = request.args.get('resolution') # Get desired resolution
    video_path = get_video_path(video_id, resolution)

    if not video_path or not os.path.exists(video_path):
        return "Video not found", 404

    def generate():
        with open(video_path, "rb") as f:
            while True:
                chunk = f.read(CHUNK_SIZE)
                if not chunk:
                    break
                yield chunk

    return Response(generate(), mimetype="video/mp4") # Adjust mimetype as needed

@app.route('/download/<video_id>')
def download_video(video_id):
    """Allows users to download the video."""
    resolution = request.args.get('resolution')
    video_path = get_video_path(video_id, resolution)

    if not video_path or not os.path.exists(video_path):
        return "Video not found", 404

    try:
        return send_file(video_path, as_attachment=True)
    except FileNotFoundError:
        abort(404)

@app.route('/thumbnail/<video_id>')
def get_thumbnail(video_id):
    """Serves a thumbnail for the video (Placeholder)."""
    # In a real implementation, you'd generate thumbnails during upload/transcoding
    # and store them.  This is just a placeholder.
    return "Thumbnail Placeholder", 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')

