import os
import threading
import queue
import time
import logging
from flask import Flask, render_template, request, Response, send_file, abort
from werkzeug.utils import secure_filename

# Configuration
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'mp4', 'avi', 'mov', 'webm'}
CHUNK_SIZE = 1024 * 1024  # 1MB chunk size
MAX_UPLOAD_SIZE = 1024 * 1024 * 1024  # 1GB max upload size

# Logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Flask app
app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_UPLOAD_SIZE

# Video metadata (in-memory for simplicity, consider a database for persistence)
videos = {}  # {video_id: {'filename': '...', 'resolution': '...', 'size': ...}}
video_id_counter = 0
video_lock = threading.Lock()

# Streaming queue (for each video, a queue of chunks to be sent)
streaming_queues = {}  # {video_id: queue.Queue()}
streaming_threads = {} # {video_id: Thread}

# Utility functions
def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def generate_video_id():
    global video_id_counter
    with video_lock:
        video_id_counter += 1
        return video_id_counter

def create_streaming_queue(video_id, filename):
    """Creates a queue and a thread to populate it with video chunks."""
    q = queue.Queue()
    streaming_queues[video_id] = q

    def chunk_generator(video_id, filename):
        try:
            with open(os.path.join(app.config['UPLOAD_FOLDER'], filename), 'rb') as f:
                while True:
                    chunk = f.read(CHUNK_SIZE)
                    if not chunk:
                        break
                    q.put(chunk)
            q.put(None)  # Signal end of stream
            logging.info(f"Video {video_id} streaming queue populated.")
        except Exception as e:
            logging.error(f"Error populating streaming queue for video {video_id}: {e}")
            # Put an error marker in the queue to signal failure
            q.put(e)

    thread = threading.Thread(target=chunk_generator, args=(video_id, filename))
    streaming_threads[video_id] = thread
    thread.daemon = True  # Allow the main thread to exit even if this is running
    thread.start()
    logging.info(f"Streaming thread started for video {video_id}")

def get_video_metadata(video_id):
    with video_lock:
        return videos.get(video_id)

def delete_video_resources(video_id):
    """Deletes the video file, metadata, queue, and thread."""
    with video_lock:
        video_data = videos.pop(video_id, None)
        if video_data:
            filename = video_data['filename']
            filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            try:
                os.remove(filepath)
                logging.info(f"Video file {filename} deleted.")
            except Exception as e:
                logging.error(f"Error deleting video file {filename}: {e}")

    if video_id in streaming_queues:
        del streaming_queues[video_id]
        logging.info(f"Streaming queue for video {video_id} deleted.")

    if video_id in streaming_threads:
        # Attempt to gracefully stop the thread (best effort)
        try:
            streaming_threads[video_id].join(timeout=5) # Wait for thread to finish
        except Exception as e:
            logging.warning(f"Error joining streaming thread for video {video_id}: {e}")
        del streaming_threads[video_id]
        logging.info(f"Streaming thread for video {video_id} deleted.")

# Routes
@app.route('/')
def index():
    with video_lock:
        video_list = list(videos.values())
    return render_template('index.html', videos=video_list)

@app.route('/upload', methods=['POST'])
def upload_video():
    if 'video' not in request.files:
        return "No video file provided", 400

    file = request.files['video']
    if file.filename == '':
        return "No video file selected", 400

    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)

        video_id = generate_video_id()
        with video_lock:
            videos[video_id] = {
                'id': video_id,
                'filename': filename,
                'resolution': '720p',  # Placeholder, implement resolution detection
                'size': os.path.getsize(filepath)
            }

        create_streaming_queue(video_id, filename)

        return f"Video uploaded successfully with ID: {video_id}", 200
    else:
        return "Invalid file type", 400

@app.route('/stream/<int:video_id>')
def stream_video(video_id):
    video_data = get_video_metadata(video_id)
    if not video_data:
        abort(404)  # Video not found

    def generate():
        q = streaming_queues.get(video_id)
        if not q:
            yield b"Error: Streaming queue not found."
            return

        try:
            while True:
                chunk = q.get()
                if chunk is None:
                    break  # End of stream
                if isinstance(chunk, Exception):
                    yield b"Error: " + str(chunk).encode()
                    break
                yield chunk
                time.sleep(0.01) # Simulate network latency and prevent overwhelming the client
        except Exception as e:
            logging.error(f"Error during streaming of video {video_id}: {e}")
            yield b"Error: " + str(e).encode()
        finally:
            logging.info(f"Streaming of video {video_id} finished.")

    return Response(generate(), mimetype='video/mp4')  # Adjust mimetype as needed

@app.route('/video/<int:video_id>')
def get_video(video_id):
    video_data = get_video_metadata(video_id)
    if not video_data:
        abort(404)

    return render_template('video.html', video=video_data)

@app.route('/delete/<int:video_id>', methods=['POST'])
def delete_video(video_id):
    video_data = get_video_metadata(video_id)
    if not video_data:
        return "Video not found", 404

    delete_video_resources(video_id)
    return "Video deleted successfully", 200

@app.route('/download/<int:video_id>')
def download_video(video_id):
    video_data = get_video_metadata(video_id)
    if not video_data:
        abort(404)

    filename = video_data['filename']
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)

    try:
        return send_file(filepath, as_attachment=True, download_name=filename)
    except FileNotFoundError:
        abort(404)

# Error handling
@app.errorhandler(404)
def page_not_found(e):
    return "Page not found", 404

@app.errorhandler(500)
def internal_server_error(e):
    logging.exception("Internal server error")
    return "Internal server error", 500

# Setup
if __name__ == '__main__':
    os.makedirs(UPLOAD_FOLDER, exist_ok=True)
    app.run(debug=True, host='0.0.0.0')

import os
import threading
import queue
import time
import logging
from flask import Flask, render_template, request, Response, send_file, abort
from werkzeug.utils import secure_filename

# Configuration
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'mp4', 'avi', 'mov', 'mkv'}
CHUNK_SIZE = 1024 * 1024  # 1MB chunk size
MAX_UPLOAD_SIZE = 1024 * 1024 * 1024  # 1GB max upload size

# Logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Flask app
app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_UPLOAD_SIZE

# Video metadata (in-memory for simplicity, consider a database for production)
videos = {}  # {video_id: {'filename': '...', 'title': '...', 'resolutions': ['720p', '1080p']}}

# Streaming queue (for each video, a queue of chunks to be sent)
streaming_queues = {}  # {video_id: queue.Queue()}

# Thread pool for video processing
video_processing_threads = []

# Ensure upload folder exists
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)


def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def generate_chunks(filepath, video_id, resolution):
    """
    Generates video chunks for streaming.  Simulates different resolutions.
    In a real application, you'd use a video processing library (e.g., ffmpeg)
    to create different resolution versions of the video.
    """
    try:
        with open(filepath, 'rb') as f:
            while True:
                chunk = f.read(CHUNK_SIZE)
                if not chunk:
                    break

                # Simulate resolution change (very basic)
                if resolution == '480p':
                    # Reduce quality (e.g., by skipping some bytes)
                    chunk = chunk[::2]  # Keep every other byte
                elif resolution == '720p':
                    # Slightly reduce quality
                    chunk = chunk[::1]
                # 1080p: No change (full quality)

                streaming_queues[video_id].put(chunk)
    except Exception as e:
        logging.error(f"Error generating chunks for {filepath}: {e}")
    finally:
        streaming_queues[video_id].put(None)  # Signal end of stream
        logging.info(f"Finished generating chunks for {filepath}")


def start_video_processing(video_id, filename):
    """Starts a thread to process the video and generate chunks for different resolutions."""
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    resolutions = ['480p', '720p', '1080p']  # Supported resolutions

    for resolution in resolutions:
        thread = threading.Thread(target=generate_chunks, args=(filepath, video_id, resolution))
        video_processing_threads.append(thread)
        thread.daemon = True  # Allow the main thread to exit even if this thread is running
        thread.start()

    videos[video_id]['resolutions'] = resolutions  # Store available resolutions


@app.route('/')
def index():
    return render_template('index.html', videos=videos)


@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return 'No file part', 400
    file = request.files['file']
    if file.filename == '':
        return 'No selected file', 400
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)

        # Generate a unique video ID (e.g., using a UUID)
        video_id = str(time.time())  # Simple ID for demonstration
        videos[video_id] = {'filename': filename, 'title': filename, 'resolutions': []}
        streaming_queues[video_id] = queue.Queue()

        start_video_processing(video_id, filename)

        return f'File uploaded successfully! Video ID: {video_id}', 200
    return 'Invalid file type', 400


@app.route('/video/<video_id>')
def video_page(video_id):
    if video_id not in videos:
        abort(404)
    return render_template('video.html', video=videos[video_id], video_id=video_id)


@app.route('/stream/<video_id>')
def stream(video_id):
    resolution = request.args.get('resolution', '1080p')  # Default to 1080p

    if video_id not in videos:
        abort(404)

    if resolution not in videos[video_id]['resolutions']:
        return f"Resolution {resolution} not available for this video.", 400

    def generate():
        try:
            while True:
                chunk = streaming_queues[video_id].get()
                if chunk is None:
                    break  # End of stream
                yield chunk
        except GeneratorExit:
            logging.info(f"Stream for video {video_id} closed by client.")
        except Exception as e:
            logging.error(f"Error streaming video {video_id}: {e}")

    return Response(generate(), mimetype='video/mp4')  # Adjust mimetype as needed


@app.route('/download/<video_id>')
def download_video(video_id):
    if video_id not in videos:
        abort(404)
    filename = videos[video_id]['filename']
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    try:
        return send_file(filepath, as_attachment=True, download_name=filename)
    except FileNotFoundError:
        abort(404)


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')

