class VideoStream:
    def __init__(self, video_path, user_id, video_id):
        self.video_path = video_path
        self.user_id = user_id
        self.video_id = video_id
        self.cap = cv2.VideoCapture(video_path)
        self.frame_rate = self.cap.get(cv2.CAP_PROP_FPS)
        self.current_frame = 0
        self.lock = threading.Lock()
        self.last_access = time.time()
        self.stop_event = threading.Event()
        self.buffer = queue.Queue(maxsize=100) # Buffer for pre-fetching frames
        self.buffer_thread = threading.Thread(target=self._fill_buffer, daemon=True)
        self.buffer_thread.start()

    def _fill_buffer(self):
        while not self.stop_event.is_set():
            with self.lock:
                if self.buffer.full():
                    time.sleep(0.1)  # Buffer full, wait a bit
                    continue

                self.cap.set(cv2.CAP_PROP_POS_FRAMES, self.current_frame)
                ret, frame = self.cap.read()

                if not ret:
                    # End of video or error
                    self.stop_event.set()
                    break

                try:
                    self.buffer.put(frame, timeout=1)  # Add frame to buffer
                except queue.Full:
                    pass # Buffer full, try again later

    def get_frame(self, frame_number):
        with self.lock:
            self.last_access = time.time()
            if frame_number < 0:
                frame_number = 0
            elif frame_number >= self.cap.get(cv2.CAP_PROP_FRAME_COUNT):
                frame_number = int(self.cap.get(cv2.CAP_PROP_FRAME_COUNT) -1)

            if frame_number != self.current_frame:
                # Seek to the requested frame
                self.current_frame = frame_number
                # Clear the buffer and restart filling
                with self.buffer.mutex:
                    self.buffer.queue.clear()
                self.stop_event.clear()
                self.buffer_thread = threading.Thread(target=self._fill_buffer, daemon=True)
                self.buffer_thread.start()

            try:
                frame = self.buffer.get(timeout=2) # Get frame from buffer
                self.current_frame += 1
                return frame
            except queue.Empty:
                logging.warning(f"Buffer empty for user {self.user_id}, video {self.video_id}, frame {frame_number}")
                return None # Handle empty buffer

    def release(self):
        with self.lock:
            self.stop_event.set()
            if self.cap.isOpened():
                self.cap.release()
            logging.info(f"Stream released for user {self.user_id}, video {self.video_id}")

