import os
import threading
import time
import queue
from flask import Flask, render_template, request, Response, send_file, abort
from flask_range import RangeRequests
import cv2

app = Flask(__name__)
range_requests = RangeRequests(app)

VIDEO_DIR = 'videos'  # Directory to store video files
CHUNK_SIZE = 1024 * 1024  # 1MB chunk size for streaming
BUFFER_SIZE = 5  # Number of chunks to buffer ahead

video_metadata = {} # Store video metadata (resolution, duration, etc.)

# Ensure video directory exists
if not os.path.exists(VIDEO_DIR):
    os.makedirs(VIDEO_DIR)

def get_video_metadata(video_path):
    """Extracts video metadata using OpenCV."""
    if video_path in video_metadata:
        return video_metadata[video_path]

    try:
        cap = cv2.VideoCapture(video_path)
        if not cap.isOpened():
            return None

        frame_width = int(cap.get(cv2.CAP_PROP_FRAME_WIDTH))
        frame_height = int(cap.get(cv2.CAP_PROP_FRAME_HEIGHT))
        fps = cap.get(cv2.CAP_PROP_FPS)
        frame_count = int(cap.get(cv2.CAP_PROP_FRAME_COUNT))
        duration = frame_count / fps if fps > 0 else 0

        metadata = {
            'width': frame_width,
            'height': frame_height,
            'fps': fps,
            'frame_count': frame_count,
            'duration': duration
        }
        video_metadata[video_path] = metadata
        cap.release()
        return metadata
    except Exception as e:
        print(f"Error getting metadata for {video_path}: {e}")
        return None

def generate_chunks(video_path, start=0):
    """Generator function to stream video chunks."""
    try:
        with open(video_path, 'rb') as f:
            f.seek(start)
            while True:
                chunk = f.read(CHUNK_SIZE)
                if not chunk:
                    break
                yield chunk
    except FileNotFoundError:
        print(f"File not found: {video_path}")
        yield None
    except Exception as e:
        print(f"Error reading file: {e}")
        yield None

def buffered_generator(video_path):
    """Buffers video chunks to handle varying connection quality."""
    chunk_queue = queue.Queue(maxsize=BUFFER_SIZE)
    stop_event = threading.Event()

    def producer():
        for chunk in generate_chunks(video_path):
            if chunk is None or stop_event.is_set():
                break
            chunk_queue.put(chunk)
        chunk_queue.put(None)  # Signal end of stream

    producer_thread = threading.Thread(target=producer)
    producer_thread.daemon = True
    producer_thread.start()

    try:
        while True:
            chunk = chunk_queue.get()
            if chunk is None:
                break
            yield chunk
    finally:
        stop_event.set()  # Ensure producer stops on client disconnect
        producer_thread.join()

@app.route('/')
def index():
    """Lists available videos."""
    videos = [f for f in os.listdir(VIDEO_DIR) if f.endswith(('.mp4', '.webm', '.avi'))]
    return render_template('index.html', videos=videos)

@app.route('/video/<filename>')
def video(filename):
    """Serves the video streaming page."""
    video_path = os.path.join(VIDEO_DIR, filename)
    if not os.path.exists(video_path):
        abort(404)

    metadata = get_video_metadata(video_path)
    if not metadata:
        abort(500, description="Failed to retrieve video metadata.")

