import threading
import time
import random

class VideoStreamServer:
    def __init__(self):
        self.videos = {}  # {video_id: {metadata, chunks}}
        self.users = {}  # {user_id: {current_video, position, paused}}
        self.lock = threading.Lock()

    def add_video(self, video_id, metadata, chunks):
        """Adds a video to the server."""
        with self.lock:
            self.videos[video_id] = {"metadata": metadata, "chunks": chunks}

    def get_video_metadata(self, video_id):
        """Returns the metadata for a given video."""
        with self.lock:
            if video_id in self.videos:
                return self.videos[video_id]["metadata"]
            else:
                return None

    def register_user(self, user_id):
        """Registers a new user."""
        with self.lock:
            self.users[user_id] = {"current_video": None, "position": 0, "paused": True}

    def start_streaming(self, user_id, video_id):
        """Starts streaming a video to a user."""
        with self.lock:
            if user_id in self.users and video_id in self.videos:
                self.users[user_id]["current_video"] = video_id
                self.users[user_id]["position"] = 0
                self.users[user_id]["paused"] = False
                return True
            else:
                return False

    def pause_streaming(self, user_id):
        """Pauses the video stream for a user."""
        with self.lock:
            if user_id in self.users:
                self.users[user_id]["paused"] = True
                return True
            else:
                return False

    def resume_streaming(self, user_id):
        """Resumes the video stream for a user."""
        with self.lock:
            if user_id in self.users:
                self.users[user_id]["paused"] = False
                return True
            else:
                return False

    def seek(self, user_id, position):
        """Seeks to a specific position in the video."""
        with self.lock:
            if user_id in self.users and self.users[user_id]["current_video"]:
                video_id = self.users[user_id]["current_video"]
                if 0 <= position <= len(self.videos[video_id]["chunks"]):
                    self.users[user_id]["position"] = position
                    return True
                else:
                    return False
            else:
                return False

    def get_chunk(self, user_id, chunk_index):
        """Returns a specific chunk of the video for a user."""
        with self.lock:
            if user_id in self.users and self.users[user_id]["current_video"]:
                video_id = self.users[user_id]["current_video"]
                if 0 <= chunk_index < len(self.videos[video_id]["chunks"]):
                    # Simulate network latency and varying connection quality
                    time.sleep(random.uniform(0.01, 0.1))  # Simulate latency
                    if random.random() < 0.05:  # Simulate packet loss
                        return None  # Indicate packet loss
                    return self.videos[video_id]["chunks"][chunk_index]
                else:
                    return None
            else:
                return None

    def stop_streaming(self, user_id):
        """Stops the video stream for a user."""
        with self.lock:
            if user_id in self.users:
                self.users[user_id]["current_video"] = None
                self.users[user_id]["position"] = 0
                self.users[user_id]["paused"] = True
                return True
            else:
                return False

