import os
import threading
import time
import queue
from flask import Flask, render_template, request, Response, send_file, abort
import cv2  # OpenCV for video processing

app = Flask(__name__)

# Configuration
VIDEO_DIR = 'videos'  # Directory to store video files
CHUNK_SIZE = 1024 * 512  # 512KB chunk size for streaming
MAX_UPLOAD_SIZE = 1024 * 1024 * 1024  # 1GB max upload size
MAX_CONCURRENT_USERS = 100  # Limit concurrent users to prevent server overload

# Threading semaphore to limit concurrent users
user_semaphore = threading.Semaphore(MAX_CONCURRENT_USERS)

# Video metadata (resolution, duration, etc.) - In-memory for simplicity, consider a database for production
video_metadata = {}

# Utility functions
def get_video_list():
    """Returns a list of video files in the VIDEO_DIR."""
    try:
        return [f for f in os.listdir(VIDEO_DIR) if os.path.isfile(os.path.join(VIDEO_DIR, f))]
    except FileNotFoundError:
        os.makedirs(VIDEO_DIR)  # Create the directory if it doesn't exist
        return []

def get_video_metadata(filename):
    """Retrieves video metadata using OpenCV."""
    filepath = os.path.join(VIDEO_DIR, filename)
    if filename in video_metadata:
        return video_metadata[filename]

    try:
        cap = cv2.VideoCapture(filepath)
        if not cap.isOpened():
            return None

        frame_width = int(cap.get(cv2.CAP_PROP_FRAME_WIDTH))
        frame_height = int(cap.get(cv2.CAP_PROP_FRAME_HEIGHT))
        fps = cap.get(cv2.CAP_PROP_FPS)
        frame_count = int(cap.get(cv2.CAP_PROP_FRAME_COUNT))
        duration = frame_count / fps if fps > 0 else 0

        metadata = {
            'width': frame_width,
            'height': frame_height,
            'fps': fps,
            'frame_count': frame_count,
            'duration': duration
        }
        video_metadata[filename] = metadata
        cap.release()
        return metadata
    except Exception as e:
        print(f"Error getting metadata for {filename}: {e}")
        return None

def generate_chunks(filepath, start=0):
    """Generates video chunks for streaming."""
    try:
        with open(filepath, 'rb') as f:
            f.seek(start)
            while True:
                chunk = f.read(CHUNK_SIZE)
                if not chunk:
                    break
                yield chunk
    except FileNotFoundError:
        print(f"File not found: {filepath}")
        yield None
    except Exception as e:
        print(f"Error reading file: {e}")
        yield None

# Routes
@app.route('/')
def index():
    """Renders the index page with a list of videos."""
    videos = get_video_list()
    return render_template('index.html', videos=videos)

@app.route('/video/<filename>')
def video(filename):
    """Renders the video player page."""
    metadata = get_video_metadata(filename)
    if not metadata:
        return "Video not found or metadata unavailable", 404
    return render_template('video.html', filename=filename, metadata=metadata)

@app.route('/stream/<filename>')
def stream(filename):
    """Streams the video file."""
    filepath = os.path.join(VIDEO_DIR, filename)

    range_header = request.headers.get('Range', None)
    start = 0
    if range_header:
        try:
            start = int(range_header.split("bytes=")[1].split("-")[0])
        except ValueError:
            pass  # Invalid range header, start from the beginning

    def generate():
        for chunk in generate_chunks(filepath, start):
            if chunk is None:
                break
            yield chunk

    try:
        file_size = os.path.getsize(filepath)
        end = file_size - 1

        response = Response(generate(), mimetype="video/mp4", status=206 if range_header else 200)
        response.headers.add('Content-Range', f'bytes {start}-{end}/{file_size}')
        response.headers.add('Accept-Ranges', 'bytes')
        return response
    except FileNotFoundError:
        abort(404)
    except Exception as e:
        print(f"Streaming error: {e}")
        abort(500)

@app.route('/upload', methods=['POST'])
def upload():
    """Handles video uploads."""
    if 'video' not in request.files:
        return "No video file provided", 400

    video_file = request.files['video']

    if video_file.filename == '':
        return "No selected file", 400

    if len(request.files['video'].read()) > MAX_UPLOAD_SIZE:
        return "File size exceeds the limit", 413

    video_file.seek(0)  # Reset file pointer after reading for size check

    filename = video_file.filename
    filepath = os.path.join(VIDEO_DIR, filename)

    try:
        video_file.save(filepath)
        video_metadata.pop(filename, None) # Remove old metadata if exists
        return "Video uploaded successfully", 200
    except Exception as e:
        print(f"Upload error: {e}")
        return f"Upload failed: {e}", 500

@app.before_request
def before_request():
    """Acquire a semaphore before each request to limit concurrent users."""
    if not user_semaphore.acquire(blocking=False):
        abort(503, "Server is currently overloaded. Please try again later.")

@app.teardown_request
def teardown_request(exception=None):
    """Release the semaphore after each request."""
    user_semaphore.release()

@app.errorhandler(503)
def service_unavailable(e):
    """Handles 503 Service Unavailable errors."""
    return "Server is currently overloaded. Please try again later.", 503

# Main
if __name__ == '__main__':
    if not os.path.exists(VIDEO_DIR):
        os.makedirs(VIDEO_DIR)
    app.run(debug=True, host='0.0.0.0')

