import os
import threading
import time
import queue
from flask import Flask, render_template, request, redirect, url_for, send_from_directory, Response
import cv2  # OpenCV for video processing

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['ALLOWED_EXTENSIONS'] = {'mp4', 'avi', 'mov'}  # Allowed video formats
app.config['MAX_CONTENT_LENGTH'] = 1024 * 1024 * 1024  # 1GB max upload size
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

video_streams = {}  # Dictionary to store video streams (filename: stream object)
stream_locks = {} # Dictionary to store locks for each stream

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in app.config['ALLOWED_EXTENSIONS']

@app.route('/', methods=['GET', 'POST'])
def upload_video():
    if request.method == 'POST':
        # check if the post request has the file part
        if 'file' not in request.files:
            return redirect(request.url)
        file = request.files['file']
        # If the user does not select a file, the browser submits an
        # empty file without a filename.
        if file.filename == '':
            return redirect(request.url)
        if file and allowed_file(file.filename):
            filename = file.filename
            filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            file.save(filepath)

            # Initialize video stream and lock
            video_streams[filename] = VideoStream(filepath)
            stream_locks[filename] = threading.Lock()

            return redirect(url_for('watch_video', filename=filename))
    return render_template('upload.html')

@app.route('/uploads/<filename>')
def send_uploaded_file(filename):
    return send_from_directory(app.config['UPLOAD_FOLDER'], filename)

@app.route('/watch/<filename>')
def watch_video(filename):
    if filename not in video_streams:
        return "Video not found."
    return render_template('watch.html', filename=filename)

def generate_frames(filename):
    """Generator function to provide video frames."""
    if filename not in video_streams:
        yield (b'--frame\r\n'
               b'Content-Type: image/jpeg\r\n\r\n' + b'\r\n') # Return empty frame
        return

    stream = video_streams[filename]
    lock = stream_locks[filename]

    while True:
        with lock: # Acquire lock before accessing the stream
            frame = stream.read_frame()
        if frame is None:
            break  # End of video or error

        yield (b'--frame\r\n'
               b'Content-Type: image/jpeg\r\n\r\n' + frame + b'\r\n')
        time.sleep(0.03) # Adjust sleep time for desired frame rate

@app.route('/video_feed/<filename>')
def video_feed(filename):
    """Route to serve the video stream."""
    return Response(generate_frames(filename),
                    mimetype='multipart/x-mixed-replace; boundary=frame')

class VideoStream:
    def __init__(self, filepath):
        self.filepath = filepath
        self.video = cv2.VideoCapture(filepath)
        self.frame_queue = queue.Queue(maxsize=100) # Queue to buffer frames
        self.stopped = False
        self.current_frame = 0
        self.total_frames = int(self.video.get(cv2.CAP_PROP_FRAME_COUNT))
        self.width  = int(self.video.get(cv2.CAP_PROP_FRAME_WIDTH))
        self.height = int(self.video.get(cv2.CAP_PROP_FRAME_HEIGHT))
        self.fps = self.video.get(cv2.CAP_PROP_FPS)

        self.start_frame_reading()

    def start_frame_reading(self):
        threading.Thread(target=self.read_frames_into_queue, daemon=True).start()

    def read_frames_into_queue(self):
        while not self.stopped:
            if self.frame_queue.full():
                time.sleep(0.01) # Wait if queue is full
                continue

            ret, frame = self.video.read()
            if not ret:
                self.stop()
                break

            try:
                self.frame_queue.put(frame, timeout=0.1) # Add frame to queue
            except queue.Full:
                pass # Ignore if queue is full

    def read_frame(self):
        try:
            frame = self.frame_queue.get(timeout=0.1)
        except queue.Empty:
            return None

        _, jpeg = cv2.imencode('.jpg', frame)
        return jpeg.tobytes()

    def seek(self, frame_number):
        """Seeks to a specific frame number."""
        if 0 <= frame_number < self.total_frames:
            self.video.set(cv2.CAP_PROP_POS_FRAMES, frame_number)
            self.current_frame = frame_number
            # Clear the queue after seeking to avoid displaying old frames
            with self.frame_queue.mutex:
                self.frame_queue.queue.clear()
        else:
            print(f"Invalid frame number: {frame_number}")

    def jump_forward(self, seconds):
        """Jumps forward by a specified number of seconds."""
        frame_jump = int(seconds * self.fps)
        new_frame = min(self.current_frame + frame_jump, self.total_frames - 1)
        self.seek(new_frame)

    def jump_backward(self, seconds):
        """Jumps backward by a specified number of seconds."""
        frame_jump = int(seconds * self.fps)
        new_frame = max(self.current_frame - frame_jump, 0)
        self.seek(new_frame)

    def stop(self):
        self.stopped = True
        self.video.release()

@app.route('/control/<filename>', methods=['POST'])
def control_video(filename):
    """Handles video control requests (pause, play, seek, etc.)."""
    if filename not in video_streams:
        return "Video not found."

    stream = video_streams[filename]
    lock = stream_locks[filename]

    action = request.form.get('action')

    with lock:
        if action == 'pause':
