import threading
import time
import random
from flask import Flask, render_template, request, Response, send_file
import os
import cv2  # OpenCV for video processing

app = Flask(__name__)

# Configuration
VIDEO_DIR = 'videos'  # Directory to store video files
CHUNK_SIZE = 1024 * 1024  # 1MB chunk size for streaming
MAX_CONCURRENT_USERS = 10  # Limit concurrent users to prevent server overload
USER_LOCK = threading.Lock()  # Lock to manage concurrent user access
CURRENT_USERS = 0

# Mock database (replace with a real database for production)
VIDEOS = {
    "video1": {"title": "Sample Video 1", "filename": "sample_video.mp4"},
    "video2": {"title": "Sample Video 2", "filename": "sample_video2.mp4"},
    # Add more videos here
}

# Create the video directory if it doesn't exist
if not os.path.exists(VIDEO_DIR):
    os.makedirs(VIDEO_DIR)

# Create sample videos if they don't exist
def create_sample_video(filename, duration=10):
    filepath = os.path.join(VIDEO_DIR, filename)
    if not os.path.exists(filepath):
        fourcc = cv2.VideoWriter_fourcc(*'mp4v')  # Codec
        out = cv2.VideoWriter(filepath, fourcc, 20.0, (640, 480))  # Output video

        for i in range(duration * 20):  # 20 frames per second
            frame = (i * 10 % 255) *  cv2.ones((480, 640, 3), dtype="uint8")
            out.write(frame.astype("uint8"))

        out.release()

create_sample_video("sample_video.mp4")
create_sample_video("sample_video2.mp4")


