    filepath = os.path.join(VIDEO_DIR, filename)
    try:
        with open(filepath, "rb") as f:
            while True:
                chunk = f.read(CHUNK_SIZE)
                if not chunk:
                    break
                yield chunk
                time.sleep(0.01)  # Simulate network latency
    except FileNotFoundError:
        print(f"File not found: {filepath}")
        yield b"Error: Video not found"
    except Exception as e:
        print(f"Error streaming video: {e}")
        yield b"Error: Streaming error"


@app.route('/stream/<filename>')
def stream_video(filename):
    global CURRENT_USERS

    with USER_LOCK:
        if CURRENT_USERS >= MAX_CONCURRENT_USERS:
            return "Server overloaded. Please try again later.", 503
        CURRENT_USERS += 1

    def cleanup():
        global CURRENT_USERS
        with USER_LOCK:
            CURRENT_USERS -= 1

    try:
        return Response(video_stream(filename), mimetype="video/mp4")
    finally:
        cleanup()


